intros a b Hle. assert (Hdir : isDirected (fun x : D => leProp x b)).
{ unfold isDirected; split; [exists b; apply (PreOrder_Reflexive _ (leProp_PreOrder PROSET) b) | intros x y Hx Hy; exists b; split; [apply (PreOrder_Reflexive _ (leProp_PreOrder PROSET) b) | split; [exact Hx | exact Hy]]]. }
assert (Hsup_b : is_supremum_of b (fun x : D => leProp x b)) by (split; [intros x Hx; exact Hx | intros u Hu; apply Hu; apply (PreOrder_Reflexive _ (leProp_PreOrder PROSET) b)]). destruct (PRESERVES_SUPREMUM (fun x : D => leProp x b) Hdir) as [sup_X [sup_Y [HsupX [HsupY Heq]]]]. assert (H_eq_supX_b : sup_X == b) by (apply (PartialOrder_Antisymmetric _ _ _ leProp_PartialOrder sup_X b); [apply (proj2 HsupX b); intros x Hx; exact Hx | apply (proj2 Hsup_b sup_X); intros x Hx; apply (proj1 HsupX x Hx)]). assert (H_eq_supY_fb : sup_Y == f b) by (eapply (Setoid_Transitive (Proset_isSetoid D') _ (f sup_X) _); [apply (Setoid_Symmetric (Proset_isSetoid D') _ _ Heq) | apply COMPAT_WITH_eqProp; exact H_eq_supX_b]). apply (PreOrder_Transitive _ (leProp_PreOrder PROSET') (f a) sup_Y (f b)); [apply (proj1 HsupY (f a)); unfold E.image; eexists a; split; [exact Hle | reflexivity] | apply (proj1 H_eq_supY_fb)].

destruct (PRESERVES_SUPREMUM (fun x : D => leProp x b) Hdir) as [s' [t [Hs' [Ht Heq]]]];
destruct Hs' as [Hup_s' Hleast_s']; destruct Ht as [Hup_t Hleast_t];
destruct (PROSET'.(leProp_PreOrder)) as [Href' Htrans']; destruct (PROSET'.(leProp_PartialOrder)) as [Hsub' Hanti'];
assert (Heq_s'_b : eqProp s' b) by
  (apply (PROSET.(leProp_PartialOrder)).(po_antisym);
   [ apply (Hleast_s' b); exact (fun x Hx => Hx)
   | apply (Hup_s' b); apply (PROSET.(leProp_PreOrder)).(PreOrder_Reflexive) b ]);
apply Htrans' with t;
 [ apply Hup_t; exists a; split; [exact Hle | reflexivity]
 | apply Hsub'; transitivity (f s'); [symmetry; exact Heq | apply COMPAT_WITH_eqProp; exact Heq_s'_b] ].

destruct (PRESERVES_SUPREMUM (fun x : D => leProp x b) Hdir) as [sup_X [sup_Y [HsupX [HsupY Hfeq]]]]. destruct (leProp_PreOrder PROSET) as [HreflD HtransD]. destruct (leProp_PreOrder PROSET') as [HreflD' HtransD']. destruct HsupX as [HupperX HleastX]. destruct HsupY as [HupperY HleastY]. pose proof (leProp_PartialOrder PROSET) as HpartialD. pose proof (leProp_PartialOrder PROSET') as HpartialD'. assert (Heq_leProp' : forall x y : D', eqProp x y -> leProp x y).
{ intros x y Heq; destruct (proj2 (HpartialD' x y) Heq) as [Hl _]; exact Hl. }
assert (H_a_supX : leProp a sup_X) by apply HupperX a Hle. assert (H_b_supX : leProp b sup_X) by apply HupperX b (HreflD b). assert (Hb_upper : forall x : D, E.In x (fun x0 : D => leProp x0 b) -> leProp x b).
{ intros x Hx; exact Hx. }
assert (H_supX_b : leProp sup_X b) by apply HleastX b Hb_upper. assert (Heq_supX_b : eqProp sup_X b) by apply (proj1 (HpartialD sup_X b) (conj H_supX_b H_b_supX)). assert (Heq_fsupX_fb : eqProp (f sup_X) (f b)) by apply COMPAT_WITH_eqProp Heq_supX_b. assert (Heq_supY_fb : eqProp sup_Y (f b)) by apply (eq_trans (eq_sym Hfeq) Heq_fsupX_fb). assert (H_supY_fb : leProp sup_Y (f b)) by apply Heq_leProp' sup_Y (f b) Heq_supY_fb. assert (H_fa_supY : leProp (f a) sup_Y) by apply HupperY (f a) (E.image_intro f (fun x : D => leProp x b) a Hle). apply (HtransD' (f a) sup_Y (f b) H_fa_supY H_supY_fb).

